167→export async function getKnowledgeSilos(
168→	orgId: string,
169→	params: { days?: number; min_sessions?: number } = {},
170→): Promise<KnowledgeSilo[]> {
171→	const { days = 30, min_sessions = 5 } = params;
172→	const org = escapeString(orgId);
173→	const d = Number(days);
174→	const minSess = Number(min_sessions);
175→
176→	const query = `
177→    SELECT
178→      project_path,
179→      any(user_id) as sole_user,
180→      COUNT(*) as sessions,
181→      CASE
182→        WHEN COUNT(*) >= 20 THEN 'high'
183→        WHEN COUNT(*) >= 10 THEN 'medium'
184→        ELSE 'low'
185→      END as risk_level
186→    FROM rudel.session_analytics
187→    WHERE ${buildDateFilter(d)}
188→      AND organization_id = '${org}'
189→      AND project_path != ''
190→    GROUP BY project_path
191→    HAVING COUNT(DISTINCT user_id) = 1
192→      AND COUNT(*) >= ${minSess}
193→    ORDER BY sessions DESC
194→  `;
195→
196→	const results = await queryClickhouse<KnowledgeSilo>(query);
197→
198→	return results.map((silo) => ({
199→		...silo,
200→		project_name: extractProjectName(silo.project_path),
201→		repository_name: extractRepositoryName(silo.project_path),
202→	}));
203→}
