205→/**
206→ * Get project activity trend over time
207→ */
208→export async function getProjectActivity(
209→	orgId: string,
210→	projectPath: string,
211→	params: { days?: number; granularity?: "day" | "week" | "month" } = {},
212→): Promise<ProjectActivity[]> {
213→	const { days = 30, granularity = "day" } = params;
214→	const org = escapeString(orgId);
215→	const pp = escapeString(projectPath);
216→	const d = Number(days);
217→
218→	let dateGrouping = "toDate(session_date)";
219→	if (granularity === "week") {
220→		dateGrouping = "toMonday(session_date)";
221→	} else if (granularity === "month") {
222→		dateGrouping = "toStartOfMonth(session_date)";
223→	}
224→
225→	const query = `
226→    WITH project_repository AS (
227→      SELECT repository, any(project_path) as project_path
228→      FROM rudel.session_analytics
229→      WHERE project_path = '${pp}'
230→        AND repository != ''
231→        AND organization_id = '${org}'
232→      LIMIT 1
233→    )
234→    SELECT
235→      toString(${dateGrouping}) as date,
236→      pr.project_path,
237→      COUNT(*) as sessions,
238→      COUNT(DISTINCT s.user_id) as unique_users
239→    FROM project_repository pr
240→    INNER JOIN rudel.session_analytics s ON s.repository = pr.repository
241→    WHERE s.${buildDateFilter(d)}
242→      AND s.organization_id = '${org}'
243→    GROUP BY ${dateGrouping}, pr.project_path
244→    ORDER BY date ASC
245→  `;
246→
247→	return queryClickhouse<ProjectActivity>(query);
248→}
