252→ */
253→export async function getProjectSummary(
254→	orgId: string,
255→	days = 30,
256→): Promise<ProjectSummary> {
257→	const org = escapeString(orgId);
258→	const d = Number(days);
259→
260→	const query = `
261→    WITH project_stats AS (
262→      SELECT
