273→      COUNT(*) as total_projects,
274→      countIf(users = 1 AND sessions >= 5) as projects_with_silos,
275→      round(AVG(users), 2) as avg_users_per_project,
276→      argMax(project_path, sessions) as most_active_project,
277→      max(sessions) as most_active_sessions
278→    FROM project_stats
279→  `;
