297→	orgId: string,
298→	projectPath: string,
299→	days = 30,
300→): Promise<ProjectDetails | null> {
301→	const org = escapeString(orgId);
302→	const pp = escapeString(projectPath);
303→	const d = Number(days);
304→
305→	const query = `
306→    SELECT
307→      any(project_path) as project_path,
308→      COUNT(*) as total_sessions,
309→      SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
310→      SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
311→      SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
312→      COUNT(DISTINCT user_id) as contributors_count,
313→      countIf(success_score < 40) as errors_count,
314→      round(AVG(actual_duration_min), 2) as avg_session_duration_min,
315→      round(AVG(success_score), 2) as success_rate,
316→      round(SUM(actual_duration_min), 2) as total_duration_min
317→    FROM rudel.session_analytics
318→    WHERE repository = (
319→      SELECT repository
320→      FROM rudel.session_analytics
321→      WHERE project_path = '${pp}'
322→        AND repository != ''
323→        AND organization_id = '${org}'
324→      LIMIT 1
325→    )
326→    AND ${buildDateFilter(d)}
327→    AND organization_id = '${org}'
328→  `;
