357→export async function getProjectContributors(
358→	orgId: string,
359→	projectPath: string,
360→	days = 30,
361→): Promise<ProjectContributor[]> {
362→	const org = escapeString(orgId);
363→	const pp = escapeString(projectPath);
364→	const d = Number(days);
365→
366→	const query = `
367→    WITH project_repository AS (
368→      SELECT repository
369→      FROM rudel.session_analytics
370→      WHERE project_path = '${pp}'
371→        AND repository != ''
372→        AND organization_id = '${org}'
373→      LIMIT 1
374→    ),
375→    project_totals AS (
376→      SELECT COUNT(*) as total_sessions
377→      FROM rudel.session_analytics
378→      WHERE repository = (SELECT repository FROM project_repository)
379→        AND ${buildDateFilter(d)}
380→        AND organization_id = '${org}'
381→    )
382→    SELECT
383→      user_id,
384→      COUNT(*) as sessions,
385→      round(SUM(actual_duration_min), 2) as total_duration_min,
