387→      toString(min(session_date)) as first_session,
388→      toString(max(session_date)) as last_session,
389→      round(COUNT(*) * 100.0 / (SELECT total_sessions FROM project_totals), 2) as contribution_percentage
390→    FROM rudel.session_analytics
391→    WHERE repository = (SELECT repository FROM project_repository)
392→      AND ${buildDateFilter(d)}
393→      AND organization_id = '${org}'
394→    GROUP BY user_id
395→    ORDER BY sessions DESC
396→  `;
397→
398→	return queryClickhouse<ProjectContributor>(query);
