401→/**
402→ * Get feature usage for a specific project
403→ */
404→export async function getProjectFeatureUsage(
405→	orgId: string,
406→	projectPath: string,
407→	days = 30,
408→): Promise<ProjectFeatureUsage> {
409→	const org = escapeString(orgId);
410→	const pp = escapeString(projectPath);
411→	const d = Number(days);
412→
413→	const repoSubquery = `(
414→    SELECT repository
415→    FROM rudel.session_analytics
416→    WHERE project_path = '${pp}'
417→      AND repository != ''
418→      AND organization_id = '${org}'
419→    LIMIT 1
420→  )`;
421→
422→	const adoptionQuery = `
423→    SELECT
424→      COUNT(*) as total_sessions,
425→      countIf(length(subagent_types) > 0) as subagents_sessions,
426→      countIf(length(skills) > 0) as skills_sessions,
427→      countIf(length(slash_commands) > 0) as slash_commands_sessions
428→    FROM rudel.session_analytics
429→    WHERE repository = ${repoSubquery}
430→    AND ${buildDateFilter(d)}
431→    AND organization_id = '${org}'
432→  `;
433→
434→	const topSubagentsQuery = `
435→    SELECT val as name, count() as count
436→    FROM rudel.session_analytics
437→    ARRAY JOIN subagent_types as val
438→    WHERE repository = ${repoSubquery}
439→      AND ${buildDateFilter(d)}
440→      AND organization_id = '${org}'
441→      AND val != ''
442→    GROUP BY val
443→    ORDER BY count DESC
444→    LIMIT 10
445→  `;
446→
447→	const topSkillsQuery = `
448→    SELECT val as name, count() as count
449→    FROM rudel.session_analytics
450→    ARRAY JOIN skills as val
451→    WHERE repository = ${repoSubquery}
452→      AND ${buildDateFilter(d)}
453→      AND organization_id = '${org}'
454→      AND val != ''
455→    GROUP BY val
456→    ORDER BY count DESC
457→    LIMIT 10
458→  `;
459→
460→	const topSlashCommandsQuery = `
461→    SELECT val as name, count() as count
462→    FROM rudel.session_analytics
463→    ARRAY JOIN slash_commands as val
464→    WHERE repository = ${repoSubquery}
465→      AND ${buildDateFilter(d)}
466→      AND organization_id = '${org}'
467→      AND val != ''
468→    GROUP BY val
469→    ORDER BY count DESC
470→    LIMIT 10
471→  `;
472→
473→	const [adoptionResults, topSubagents, topSkills, topSlashCommands] =
474→		await Promise.all([
475→			queryClickhouse<{
476→				total_sessions: number;
477→				subagents_sessions: number;
478→				skills_sessions: number;
479→				slash_commands_sessions: number;
480→			}>(adoptionQuery),
481→			queryClickhouse<{ name: string; count: number }>(topSubagentsQuery),
482→			queryClickhouse<{ name: string; count: number }>(topSkillsQuery),
483→			queryClickhouse<{ name: string; count: number }>(topSlashCommandsQuery),
484→		]);
485→
486→	if (adoptionResults.length === 0) {
487→		return {
488→			subagents_adoption_rate: 0,
489→			skills_adoption_rate: 0,
490→			slash_commands_adoption_rate: 0,
491→			top_subagents: [],
492→			top_skills: [],
493→			top_slash_commands: [],
494→		};
495→	}
496→
497→	const [stats] = adoptionResults;
498→	if (!stats)
499→		return {
500→			subagents_adoption_rate: 0,
501→			skills_adoption_rate: 0,
502→			slash_commands_adoption_rate: 0,
503→			top_subagents: [],
504→			top_skills: [],
505→			top_slash_commands: [],
506→		};
507→	return {
508→		subagents_adoption_rate:
509→			stats.total_sessions > 0
510→				? (stats.subagents_sessions / stats.total_sessions) * 100
511→				: 0,
512→		skills_adoption_rate:
513→			stats.total_sessions > 0
514→				? (stats.skills_sessions / stats.total_sessions) * 100
515→				: 0,
516→		slash_commands_adoption_rate:
517→			stats.total_sessions > 0
518→				? (stats.slash_commands_sessions / stats.total_sessions) * 100
519→				: 0,
520→		top_subagents: topSubagents,
521→		top_skills: topSkills,
522→		top_slash_commands: topSlashCommands,
523→	};
524→}
