30→function saveProjectsConfig(config: ProjectsConfig): void {
31→	const dir = getConfigDir();
32→	if (!existsSync(dir)) {
33→		mkdirSync(dir, { recursive: true, mode: 0o700 });
34→	}
35→	writeFileSync(getProjectsConfigPath(), JSON.stringify(config, null, 2), {
36→		mode: 0o600,
37→	});
38→}
