78→	cwd: string,
79→	organizationId: string,
80→): Promise<void> {
81→	const key = await getProjectKey(cwd);
82→	const config = loadProjectsConfig();
83→	config.projects[key] = { organizationId };
84→	saveProjectsConfig(config);
